import { useEffect, useState, useCallback } from "react";
import {
  getUsers,
  createEmployee,
  updateUser,
  blockUser,
  deleteEmployee,
} from "../../api/adminApi";
import DashboardLayout from "../../components/layout/DashboardLayout";
import ErrorModal from "../../components/ErrorModal";
import { Pencil, Plus, Trash2, X, Save } from "lucide-react";

/* ─── ROLE COLOURS ─── */
const ROLE_META = {
  ADMIN:   { color: "#e8a020", bg: "rgba(232,160,32,0.13)"  },
  LOGIST:  { color: "#9b72f5", bg: "rgba(155,114,245,0.13)" },
  COURIER: { color: "#2ec88a", bg: "rgba(46,200,138,0.13)"  },
  CLIENT:  { color: "#4da8f5", bg: "rgba(77,168,245,0.13)"  },
};

function RoleBadge({ role }) {
  const m = ROLE_META[role?.toUpperCase()] || { color: "#94a3b8", bg: "rgba(148,163,184,0.1)" };
  return (
    <span style={{
      display: "inline-flex", alignItems: "center", gap: 5,
      padding: "3px 11px", borderRadius: 99,
      background: m.bg, color: m.color,
      fontSize: "0.7rem", fontWeight: 700,
      fontFamily: "'Syne',sans-serif", letterSpacing: "0.06em",
    }}>
      <span style={{ width: 5, height: 5, borderRadius: "50%", background: m.color }} />
      {role}
    </span>
  );
}

/* Статус прямо в таблице — select с цветом */
function StatusSelect({ user, onChange }) {
  const active = user.status !== "Заблокирован";
  return (
    <select
      value={user.status}
      onChange={e => onChange(user.id, e.target.value === "Заблокирован", e.target.value)}
      style={{
        background: active ? "rgba(46,200,138,0.12)" : "rgba(239,68,68,0.12)",
        color:       active ? "#2ec88a" : "#f87171",
        border:      `1px solid ${active ? "rgba(46,200,138,0.3)" : "rgba(239,68,68,0.3)"}`,
        borderRadius: 99, padding: "3px 10px", fontSize: "0.75rem",
        fontWeight: 600, fontFamily: "'DM Sans',sans-serif",
        cursor: "pointer", outline: "none", appearance: "none",
        WebkitAppearance: "none", minWidth: 130, textAlign: "center",
      }}
    >
      <option value="Активен">● Активен</option>
      <option value="Заблокирован">⛔ Заблокирован</option>
    </select>
  );
}

/* ─── STYLES ─── */
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Syne:wght@500;700;800&family=DM+Sans:wght@300;400;500&display=swap');

.up-page {
  font-family: 'DM Sans', sans-serif;
  padding: 28px 32px;
  min-height: 100vh;
  background: #0d0d14;
  color: #dde1ea;
}

/* HEADER */
.up-header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 28px;
  flex-wrap: wrap;
}
.up-title {
  font-family: 'Syne', sans-serif;
  font-size: 2rem;
  font-weight: 800;
  margin: 0 0 2px 0;
  background: linear-gradient(120deg,#c7d2fe 0%,#a78bfa 40%,#67e8f9 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.up-subtitle {
  font-size: 0.82rem;
  color: #4a5069;
  margin: 0;
  font-weight: 300;
}
.up-add-btn {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  background: linear-gradient(135deg,#6d28d9,#2563eb);
  color: #fff;
  border: none;
  border-radius: 11px;
  padding: 11px 22px;
  font-family: 'Syne', sans-serif;
  font-weight: 700;
  font-size: 0.82rem;
  letter-spacing: 0.04em;
  cursor: pointer;
  transition: all .2s;
  box-shadow: 0 0 18px rgba(109,40,217,.35);
}
.up-add-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 0 28px rgba(109,40,217,.55);
}

/* STATS */
.up-stats {
  display: flex;
  gap: 12px;
  margin-bottom: 22px;
  flex-wrap: wrap;
}
.up-stat {
  background: #161622;
  border: 1px solid #252535;
  border-radius: 12px;
  padding: 12px 20px;
  display: flex;
  align-items: center;
  gap: 10px;
}
.up-stat-val {
  font-family: 'Syne', sans-serif;
  font-size: 1.5rem;
  font-weight: 800;
  color: #c7d2fe;
  line-height: 1;
}
.up-stat.s-green .up-stat-val { color: #2ec88a; }
.up-stat.s-red   .up-stat-val { color: #f87171; }
.up-stat-lbl {
  font-size: 0.78rem;
  color: #4a5069;
  font-weight: 400;
}

/* FILTERS */
.up-filters {
  display: flex;
  gap: 10px;
  margin-bottom: 20px;
  flex-wrap: wrap;
  align-items: center;
}
.up-search {
  flex: 1;
  min-width: 220px;
  background: #161622;
  border: 1px solid #252535;
  border-radius: 10px;
  color: #c7d2fe;
  padding: 9px 14px;
  font-family: 'DM Sans', sans-serif;
  font-size: 0.84rem;
  outline: none;
  transition: border-color .2s;
}
.up-search::placeholder { color: #303048; }
.up-search:focus { border-color: #6d28d9; }
.up-sel {
  background: #161622;
  border: 1px solid #252535;
  border-radius: 10px;
  color: #8b8faa;
  padding: 9px 14px;
  font-family: 'DM Sans', sans-serif;
  font-size: 0.84rem;
  outline: none;
  cursor: pointer;
  min-width: 150px;
  transition: border-color .2s;
}
.up-sel:focus { border-color: #6d28d9; }
.up-sel option { background: #161622; }

/* TABLE */
.up-table-wrap {
  background: #161622;
  border: 1px solid #252535;
  border-radius: 16px;
  overflow: hidden;
  box-shadow: 0 20px 50px rgba(0,0,0,.45);
}
.up-table {
  width: 100%;
  border-collapse: collapse;
}
.up-table thead tr {
  background: #0d0d18;
  border-bottom: 1px solid #252535;
}
.up-table th {
  padding: 13px 16px;
  text-align: left;
  font-family: 'Syne', sans-serif;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: .1em;
  text-transform: uppercase;
  color: #3b3d58;
}
.up-table tbody tr {
  border-bottom: 1px solid #1b1b2c;
  transition: background .15s;
}
.up-table tbody tr:last-child { border-bottom: none; }
.up-table tbody tr:hover { background: rgba(109,40,217,.05); }
.up-table td { padding: 12px 16px; vertical-align: middle; }

.up-id { font-family:'Syne',sans-serif; font-size:.75rem; color:#373756; font-weight:700; }
.up-user-cell { display:flex; align-items:center; gap:11px; }
.up-avatar {
  width:36px; height:36px; border-radius:10px;
  display:flex; align-items:center; justify-content:center;
  font-family:'Syne',sans-serif; font-weight:800; font-size:.9rem;
  flex-shrink:0;
}
.up-name { font-size:.87rem; font-weight:500; color:#dde1ea; }
.up-email { font-size:.74rem; color:#3b3d58; margin-top:1px; }
.up-phone { font-size:.83rem; color:#4a5069; }

.up-actions { display:flex; gap:6px; }
.up-icon-btn {
  width:32px; height:32px; border-radius:8px;
  border:1px solid #252535; background:#0d0d14;
  color:#4a5069; cursor:pointer; display:flex;
  align-items:center; justify-content:center;
  transition:all .18s;
}
.up-icon-btn.edit:hover { border-color:#3b82f6; color:#3b82f6; background:rgba(59,130,246,.1); }
.up-icon-btn.del:hover  { border-color:#ef4444; color:#ef4444; background:rgba(239,68,68,.1); }
.up-icon-btn:hover { transform:scale(1.1); }

.up-empty { text-align:center; padding:52px; color:#303048; font-size:.88rem; }
.up-loading { text-align:center; padding:52px; color:#4a5069; font-size:.88rem; }

/* OVERLAY */
.up-overlay {
  position:fixed; inset:0;
  background:rgba(0,0,0,.72);
  backdrop-filter:blur(7px);
  display:flex; align-items:center; justify-content:center;
  z-index:999;
  animation:fadeIn .18s;
}
@keyframes fadeIn { from{opacity:0} to{opacity:1} }

/* MODAL */
.up-modal {
  background:#161622;
  border:1px solid #252535;
  border-radius:18px;
  padding:0;
  width:100%;
  max-width:460px;
  box-shadow:0 40px 80px rgba(0,0,0,.6);
  animation:slideUp .22s;
  overflow:hidden;
}
@keyframes slideUp {
  from{transform:translateY(18px);opacity:0}
  to{transform:translateY(0);opacity:1}
}
.up-modal-header {
  display:flex; align-items:center; justify-content:space-between;
  padding:22px 26px 18px;
  border-bottom:1px solid #1e1e2e;
}
.up-modal-header h2 {
  font-family:'Syne',sans-serif;
  font-size:1.15rem; font-weight:800; margin:0;
  color:#c7d2fe;
}
.up-close {
  background:transparent; border:none;
  color:#4a5069; cursor:pointer; padding:4px;
  display:flex; align-items:center; justify-content:center;
  border-radius:7px; transition:all .15s;
}
.up-close:hover { color:#f87171; background:rgba(239,68,68,.1); }

.up-form {
  padding:22px 26px;
  display:flex; flex-direction:column; gap:14px;
}
.up-row2 { display:grid; grid-template-columns:1fr 1fr; gap:12px; }
.up-field { display:flex; flex-direction:column; gap:5px; }
.up-field label {
  font-size:.7rem; font-weight:700;
  letter-spacing:.09em; text-transform:uppercase;
  color:#373756; font-family:'Syne',sans-serif;
}
.up-field input,
.up-field select {
  background:#0d0d14;
  border:1px solid #252535;
  border-radius:9px;
  color:#dde1ea;
  padding:10px 13px;
  font-family:'DM Sans',sans-serif;
  font-size:.88rem;
  outline:none;
  transition:border-color .2s, box-shadow .2s;
}
.up-field input:focus,
.up-field select:focus {
  border-color:#6d28d9;
  box-shadow:0 0 0 3px rgba(109,40,217,.15);
}
.up-field input::placeholder { color:#252535; }
.up-field select option { background:#0d0d14; }

.up-modal-footer {
  padding:16px 26px 22px;
  display:flex; gap:10px; justify-content:flex-end;
  border-top:1px solid #1e1e2e;
}
.up-btn-cancel {
  background:transparent; border:1px solid #252535;
  color:#4a5069; border-radius:9px;
  padding:9px 18px; cursor:pointer;
  font-family:'DM Sans',sans-serif; font-size:.84rem;
  transition:all .18s;
}
.up-btn-cancel:hover { border-color:#4a5069; color:#8b8faa; }
.up-btn-save {
  display:inline-flex; align-items:center; gap:6px;
  background:linear-gradient(135deg,#6d28d9,#2563eb);
  border:none; color:#fff; border-radius:9px;
  padding:9px 22px; cursor:pointer;
  font-family:'Syne',sans-serif; font-weight:700;
  font-size:.84rem;
  box-shadow:0 0 14px rgba(109,40,217,.3);
  transition:all .2s;
}
.up-btn-save:hover { box-shadow:0 0 22px rgba(109,40,217,.5); transform:translateY(-1px); }
`;

/* ─── COMPONENT ─── */
export default function UsersPage() {
  const [users,   setUsers]   = useState([]);
  const [loading, setLoading] = useState(false);
  const [filters, setFilters] = useState({ role: "", status: "" });
  const [search,  setSearch]  = useState("");

  const [formOpen,      setFormOpen]      = useState(false);
  const [editMode,      setEditMode]      = useState(false);
  const [selectedUser,  setSelectedUser]  = useState(null);
  const [formData,      setFormData]      = useState({
    firstName: "", lastName: "", email: "", password: "", phone: "", roleName: "COURIER",
  });
  const [errorModal, setErrorModal] = useState({ isOpen: false, message: "" });

  const loadUsers = useCallback(async () => {
    setLoading(true);
    try {
      const params = {};
      if (filters.role)   params.roleName   = filters.role;
      if (filters.status) params.statusName = filters.status;
      const data = await getUsers(params);
      setUsers(data.content || []);
    } catch (e) {
      setErrorModal({ isOpen: true, message: e.message });
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => { loadUsers(); }, [loadUsers]);

  /* Клиентский поиск */
  const visible = users.filter(u => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (
      u.fullName?.toLowerCase().includes(q) ||
      u.email?.toLowerCase().includes(q) ||
      u.phone?.includes(q)
    );
  });

  const openCreate = () => {
    setEditMode(false);
    setFormData({ firstName: "", lastName: "", email: "", password: "", phone: "", roleName: "COURIER" });
    setFormOpen(true);
  };

  const openEdit = (u) => {
    const parts = (u.fullName || "").split(" ");
    setEditMode(true);
    setSelectedUser(u);
    setFormData({
      firstName: parts[0] || "",
      lastName:  parts.slice(1).join(" ") || "",
      email:     u.email  || "",
      password:  "",
      phone:     u.phone  || "",
      roleName:  u.role   || "COURIER",
    });
    setFormOpen(true);
  };

  const handleSubmit = async () => {
    const fullName = [formData.firstName.trim(), formData.lastName.trim()].filter(Boolean).join(" ");
    if (!fullName) { setErrorModal({ isOpen: true, message: "Введите имя сотрудника." }); return; }
    try {
      const payload = { ...formData, fullName };
      if (editMode) await updateUser(selectedUser.id, payload);
      else          await createEmployee(payload);
      setFormOpen(false);
      loadUsers();
    } catch (e) {
      setErrorModal({ isOpen: true, message: e.message });
    }
  };

  /* Мгновенная перерисовка — оптимистичное обновление */
  const handleStatusChange = async (id, block, newStatus) => {
    setUsers(prev => prev.map(u => u.id === id ? { ...u, status: newStatus } : u));
    try { await blockUser(id, block); }
    catch (e) {
      /* откатываем */
      setUsers(prev => prev.map(u => u.id === id ? { ...u, status: block ? "Активен" : "Заблокирован" } : u));
      setErrorModal({ isOpen: true, message: e.message });
    }
  };

  const handleDelete = async (u) => {
    if (u.role?.toUpperCase() === "ADMIN") {
      setErrorModal({ isOpen: true, message: "Нельзя удалить пользователя с ролью ADMIN." });
      return;
    }
    if (!window.confirm(`Удалить ${u.fullName}? Это необратимо.`)) return;
    try {
      await deleteEmployee(u.id);
      setUsers(prev => prev.filter(x => x.id !== u.id));
    } catch (e) {
      setErrorModal({ isOpen: true, message: e.message });
    }
  };

  const stats = {
    total:   users.length,
    active:  users.filter(u => u.status === "Активен").length,
    blocked: users.filter(u => u.status === "Заблокирован").length,
  };

  return (
    <DashboardLayout>
      <style>{CSS}</style>
      <div className="up-page">

        {/* HEADER */}
        <div className="up-header">
          <div>
            <h1 className="up-title">Пользователи</h1>
            <p className="up-subtitle">Управление учётными записями сотрудников</p>
          </div>
          <button className="up-add-btn" onClick={openCreate}>
            <Plus size={15} strokeWidth={2.5} /> Добавить сотрудника
          </button>
        </div>

        {/* STATS */}
        <div className="up-stats">
          <div className="up-stat">
            <span className="up-stat-val">{stats.total}</span>
            <span className="up-stat-lbl">Всего</span>
          </div>
          <div className="up-stat s-green">
            <span className="up-stat-val">{stats.active}</span>
            <span className="up-stat-lbl">Активных</span>
          </div>
          <div className="up-stat s-red">
            <span className="up-stat-val">{stats.blocked}</span>
            <span className="up-stat-lbl">Заблокировано</span>
          </div>
        </div>

        {/* FILTERS */}
        <div className="up-filters">
          <input className="up-search" placeholder="🔍  Поиск по имени, email, телефону…"
            value={search} onChange={e => setSearch(e.target.value)} />
          <select className="up-sel" value={filters.role}
            onChange={e => setFilters(f => ({ ...f, role: e.target.value }))}>
            <option value="">Все роли</option>
            <option value="ADMIN">ADMIN</option>
            <option value="LOGIST">LOGIST</option>
            <option value="COURIER">COURIER</option>
            <option value="CLIENT">CLIENT</option>
          </select>
          <select className="up-sel" value={filters.status}
            onChange={e => setFilters(f => ({ ...f, status: e.target.value }))}>
            <option value="">Все статусы</option>
            <option value="Активен">Активен</option>
            <option value="Заблокирован">Заблокирован</option>
          </select>
        </div>

        {/* TABLE */}
        <div className="up-table-wrap">
          {loading ? <div className="up-loading">Загрузка…</div> : (
            <table className="up-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Сотрудник</th>
                  <th>Телефон</th>
                  <th>Роль</th>
                  <th>Статус</th>
                  <th>Действия</th>
                </tr>
              </thead>
              <tbody>
                {visible.length === 0 ? (
                  <tr><td colSpan={6} className="up-empty">Ничего не найдено</td></tr>
                ) : visible.map(u => {
                  const m = ROLE_META[u.role?.toUpperCase()];
                  return (
                    <tr key={u.id}>
                      <td><span className="up-id">#{u.id}</span></td>
                      <td>
                        <div className="up-user-cell">
                          <div className="up-avatar" style={{ background: m?.bg || "#1a1a2e" }}>
                            <span style={{ color: m?.color || "#9ca3af" }}>
                              {(u.fullName || "?")[0].toUpperCase()}
                            </span>
                          </div>
                          <div>
                            <div className="up-name">{u.fullName}</div>
                            <div className="up-email">{u.email}</div>
                          </div>
                        </div>
                      </td>
                      <td><span className="up-phone">{u.phone || "—"}</span></td>
                      <td><RoleBadge role={u.role} /></td>
                      <td>
                        <StatusSelect user={u} onChange={handleStatusChange} />
                      </td>
                      <td>
                        <div className="up-actions">
                          <button className="up-icon-btn edit" title="Редактировать" onClick={() => openEdit(u)}>
                            <Pencil size={14} />
                          </button>
                          <button className="up-icon-btn del" title="Удалить" onClick={() => handleDelete(u)}>
                            <Trash2 size={14} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>

        {/* MODAL */}
        {formOpen && (
          <div className="up-overlay" onClick={e => e.target === e.currentTarget && setFormOpen(false)}>
            <div className="up-modal">
              <div className="up-modal-header">
                <h2>{editMode ? "Редактировать пользователя" : "Новый сотрудник"}</h2>
                <button className="up-close" onClick={() => setFormOpen(false)}><X size={18} /></button>
              </div>

              <div className="up-form">
                <div className="up-row2">
                  <div className="up-field">
                    <label>Имя</label>
                    <input placeholder="Иван" value={formData.firstName}
                      onChange={e => setFormData(f => ({ ...f, firstName: e.target.value }))} />
                  </div>
                  <div className="up-field">
                    <label>Фамилия</label>
                    <input placeholder="Иванов" value={formData.lastName}
                      onChange={e => setFormData(f => ({ ...f, lastName: e.target.value }))} />
                  </div>
                </div>

                <div className="up-field">
                  <label>Email</label>
                  <input type="email" placeholder="user@example.com" value={formData.email}
                    onChange={e => setFormData(f => ({ ...f, email: e.target.value }))} />
                </div>

                {!editMode && (
                  <div className="up-field">
                    <label>Пароль</label>
                    <input type="password" placeholder="••••••••" value={formData.password}
                      onChange={e => setFormData(f => ({ ...f, password: e.target.value }))} />
                  </div>
                )}

                <div className="up-field">
                  <label>Телефон</label>
                  <input placeholder="+375 29 000-00-00" value={formData.phone}
                    onChange={e => setFormData(f => ({ ...f, phone: e.target.value }))} />
                </div>

                {!editMode && (
                  <div className="up-field">
                    <label>Роль</label>
                    <select value={formData.roleName}
                      onChange={e => setFormData(f => ({ ...f, roleName: e.target.value }))}>
                      <option value="COURIER">COURIER</option>
                      <option value="LOGIST">LOGIST</option>
                    </select>
                  </div>
                )}
              </div>

              <div className="up-modal-footer">
                <button className="up-btn-cancel" onClick={() => setFormOpen(false)}>Отмена</button>
                <button className="up-btn-save" onClick={handleSubmit}>
                  <Save size={14} /> Сохранить
                </button>
              </div>
            </div>
          </div>
        )}

        <ErrorModal
          isOpen={errorModal.isOpen}
          title="Ошибка"
          message={errorModal.message}
          onClose={() => setErrorModal({ isOpen: false, message: "" })}
        />
      </div>
    </DashboardLayout>
  );
}
